var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"네? 부대로 정상 출근하신다고요? 정말 고향에 가지 않아도 괜찮으신 겁니까?","JPN":"はい？　部隊に通常出勤ですか？　実家に戻らなくて本当に大丈夫ですか？","ENG":"What? You're coming to work today? Are you sure you don't need to go see your family?","TWN":"咦？您說要讓部隊正常出動？您不回故鄉真的沒關係嗎？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지금이라도 중장님께 말씀을 드리면, 바로 휴가를 내 주실 겁니다.","JPN":"今なら、中将に報告すればすぐに休暇がもらえるはずです。","ENG":"I'm sure it's not too late for you to request leave with the Lieutenant General.","TWN":"現在還來得及，只要跟中將大人說一下，中將大人應該馬上會批准休假的。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아냐, 됐어.","JPN":"いや、いいんだ。","ENG":"It's fine.","TWN":"不，不用了。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그리고 이 얘기는 중장님께는 비밀로 해줬으면 좋겠어.","JPN":"それと、この話は中将には内緒にしてほしい。","ENG":"And I'd appreciate it if you could keep this a secret from the Lieutenant General.","TWN":"還有，這件事我希望你能對中將保密。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"많이 바쁘실 테니 말이야.","JPN":"忙しいようだしな。","ENG":"I'm sure she's busy enough as it is.","TWN":"畢竟她很忙。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"바텐더. 늘 마시던 걸로.","JPN":"マスター、いつもの。","ENG":"Bartender. Give me the usual.","TWN":"酒保，老樣子。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L14_1","type":"dialog","speaker":"MASTER_NPC_NULL_NULL","text":{"KOREA":"자네가 늘 마시던 거? 밀크셰이크 말인가?","JPN":"お前のいつものって何だ？　ミルクセーキか？","ENG":"The usual? You mean a milkshake?","TWN":"老樣子？你是指奶昔嗎？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"로망이 없구만. 보는 눈도 있는데 이런 대사는 멋있게 좀 받아줘야 하는 거 아닌가?","JPN":"ロマンがないな。他の客もいるんだし、もう少しうまく言い返してくれてもいいんじゃないか。","ENG":"Come on, don't kill the vibe. I've got eyes on me. Can't you just go with the flow?","TWN":"你還真是不浪漫啊，旁邊還有人看著呢，這種時候不是應該把台詞帥氣地接下去嗎？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_NPC_NULL_NULL","text":{"KOREA":"몇 년째 팁도 한 푼 안 내는 수전노 주제에 바라는 것도 많군.","JPN":"何年もチップすら払わない守銭奴のくせに、文句を言うんじゃない。","ENG":"Says the cheapskate who hasn't tipped for years.","TWN":"一個幾年都沒給過小費的守財奴，要求倒是很多。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_NPC_NULL_NULL","text":{"KOREA":"자네 딸의 부탁만 아니었으면 당장 쫓아냈을 거야.","JPN":"お前の娘の頼みじゃなかったら、さっさと追い出したい所だ。","ENG":"If it weren't for your daughter's request, I would've kicked you out a long time ago.","TWN":"要不是看在你女兒的面子上，我早就把你趕出去了。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하하, 아빠가 항상 딸의 도움만 받는군.","JPN":"はは、父親になって娘に助けられてばかりだな。","ENG":"Hah hah, I guess my daughter's always helping out her old man.","TWN":"哈哈，當爸爸的總是會沾女兒的光呢。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그나저나 이 친구는 너무 많이 마신 것 같은데? 완전히 맛이 갔는걸?","JPN":"ところで、こいつ飲みすぎじゃないか？　完全に酔っ払ってるぞ？","ENG":"By the way, this fella seems to have outdone himself. He's wasted.","TWN":"話說這位朋友是不是喝多了？有點不太對勁啊？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 무슨 일이라도 있는 건가?","JPN":"なぁ、何かあったのか？","ENG":"Hey buddy, something wrong?","TWN":"嘿，你怎麼了嗎？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런 거 없어. 그냥 목이 마를 뿐이야.","JPN":"何もないんだ。ただ喉が乾いただけだ。","ENG":"Everything's fine... I'm just thirsty.","TWN":"沒什麼。只是有點口渴了。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그리고 용병인 것 같은데...... 함부로 말 걸지 마.","JPN":"それに、傭兵のようだが……俺に軽々しく話しかけるな。","ENG":"You look like a mercenary... Don't call me buddy...","TWN":"然後你看起來好像是個傭兵……不要隨便跟我搭話。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"난 용병을 싫어해.","JPN":"俺は傭兵が嫌いなんだよ。","ENG":"I hate you mercs.","TWN":"我討厭傭兵。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래? 편견이 심한 친구로군.","JPN":"そうか？　酷い偏見を持っているんだな。","ENG":"Is that right? You sound like one prejudiced fella.","TWN":"是嗎？真是位偏見嚴重的朋友呢。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......그런가 보지, 마음대로 생각해.","JPN":"……そうかな。勝手に言ってろ。","ENG":"Sure, I guess. Whatever floats your boat.","TWN":"……是喔，隨便你怎麼想。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"가늠쇠와 눈을 수평에 맞춰봐.","JPN":"照準器と目を水平に合わせてみろ。","ENG":"Now line up the sight with your eyes.","TWN":"眼睛要和準星處於一個水平線上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_03"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"숨을 절반만 머금고, 천천히 방아쇠를 당기는 거야.","JPN":"半分息を吸って、ゆっくり引き金を引いてみろ。","ENG":"Hold your breath gently and slowly squeeze the trigger.","TWN":"屏住呼吸，慢慢扣動扳機。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SHOTGUN_RELOAD_SMALL"},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"콜록 콜록!","JPN":"ゲホゲホ！","ENG":"*Cough, cough*","TWN":"咳咳！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"크으, 아깝게 위로 맞았네. 역시 조정이 좀 필요한가?","JPN":"くう、惜しくも上に当たったな。やっぱり調整が必要なのか？","ENG":"Ah, so close. Missed by a hair. I guess it needs to be zeroed in a bit more.","TWN":"啊，可惜了，打偏到上面去了。果然還需要再調整一下嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"총 이리 줘봐. 내가 하는 거 잘 보고, 다음 번엔 네가 직접 눈금을 맞춰.","JPN":"銃を貸してごらん。私がやることをよく見て、次は自分で照準を合わせてみろ。","ENG":"Hand me the gun. Watch me carefully, and try to adjust the sight yourself next time.","TWN":"把槍給我。我先給你示範一下，下次開始你要自己調整。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"전 총 쏘는 법 안 배울래요, 아버지. 소질이 없다고요.","JPN":"父さん、俺、銃の撃ち方なんて習いたくないよ。素質がないんだ。","ENG":"I don't want to learn how to shoot, Dad. I'm no good at it.","TWN":"爸爸，我不想學射擊了，我沒有天賦。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"하하, 총을 다루는 사람들이 모두 타고난 명사수는 아니야.","JPN":"はは。銃を扱う者たちが皆、名射手なわけではないぞ。","ENG":"Hah hah, not everyone who carries a gun was born a sharpshooter.","TWN":"哈哈，用槍的人不會天生就是神槍手。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"단지, 그렇게 해야 자신이 원하는 걸 지킬 수 있기 때문에 배우는 거지.","JPN":"ただ、射撃を学ぶことで自分の大切なものを守れるんだ。","ENG":"They learn how to shoot because they want to protect what they value.","TWN":"他們學習射擊，只是為了守護自己想要守護的事物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"평화롭던 시절엔 이걸 들고 칠면조사냥이나 다녔었겠지만......","JPN":"平和だった時代にはこれを持って七面鳥狩りなんかしてたかもしれないが……","ENG":"I guess back when things were peaceful, we'd have hunted turkeys with this thing...","TWN":"雖說和平的時代也會用來狩獵火雞之類的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"지금은 언제 이게 필요해질지 모르니까 말이야.","JPN":"今はこれがいつ必要になるかわからない時代だからな。","ENG":"But nowadays, you never know when you'll need this.","TWN":"但我現在也不知道什麼時候會用到它。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"우린 어느 때보다 이런 재능이 필요한 시기를 살고 있어.","JPN":"私たちはどの時代より、こういう才能が必要な時代に生きている。","ENG":"We live in a world where this sort of skill is more important than ever.","TWN":"我們生活的這個時代，比以往任何時候都更需要這種才能。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"난 네가 가족을 지킬 수 있을 만큼 강해져 줬으면 좋겠구나.","JPN":"私はお前が家族を守れるほど強くなってほしいんだ。","ENG":"I hope you'll grow strong enough to protect our family.","TWN":"我希望你能變強到能夠保護家人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"제가 우리 가족을요?","JPN":"俺が家族を？","ENG":"Me? Protect our family?","TWN":"我來保護家人嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"......그렇게 할 수 있을까요?","JPN":"……そんなことができるのかな？","ENG":"You think I can really do that?","TWN":"……我能做到嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"물론이지. 하지만 그러려면 우선, 총을 다루는 법부터 배우는 게 우선이지.","JPN":"もちろんさ。だが、そうするためにはまず銃の撃ち方を学ばないといけないんだ。","ENG":"Of course. But first, you'll have to learn how to handle a gun properly.","TWN":"那當然。但為了保護家人，首先，你得學會如何使用槍支。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"의지도 중요하지만, 침식체 같은 괴물들한테서 가족을 지키려면 맨주먹으론 어림도 없잖냐.","JPN":"意志も大切だが、侵食体みたいな怪物から家族を守るためには素手では無理だからな。","ENG":"No matter how courageous you might be, you can't protect anyone from monsters like C.O.s with your bare fists.","TWN":"雖然意志也很重要，但你不可能赤手空拳，從侵蝕體手下保護家人的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"아버지. 하지만 정작 당신은 가족이 당신을 가장 필요로 하는 때에 나타나지 않았죠.","JPN":"父さん。でも、家族があなたを一番必要としたときに、あなたは現れなかった。","ENG":"Dad. But you never appeared when your family needed you the most.","TWN":"父親。但在家人真正需要你的時候，你並沒有出現。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"돈에 정신이 팔린 나머지, 정작 가족을 지키는 건 뒷전이었던 거야. 당신은.","JPN":"あなたは、お金に気を取られてしまったせいで家族を守ることを後回しにしたんだ。","ENG":"You were so preoccupied with making money that you couldn't care less about protecting your family. That's how you were.","TWN":"你的心思一直都沉迷在金錢上，把真正需要守護的家人拋在腦後。你就是這樣的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이런, 깜박 잠들었나.","JPN":"おっと、うっかり寝てしまってたか。","ENG":"Huh? Did I doze off?","TWN":"嗯，我不小心睡著了啊。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"오래도 잤지. 잠꼬대도 하던걸?","JPN":"結構寝てたよ。寝言も言ってたな。","ENG":"You were completely out, actually. You were even talking in your sleep.","TWN":"睡很久了，還了夢話呢。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아직도 있었나?","JPN":"まだいたのか？","ENG":"You're still here?","TWN":"你還在啊？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......남의 잠꼬대를 듣고 있다니, 쓸데없는 취미로군. 용병이라 그런가?","JPN":"……人の寝言を聞くなんて、悪趣味だな。傭兵だからか？","ENG":"And you were listening to me sleep talk... Right, not creepy at all. Must be a mercenary thing, huh?","TWN":"……居然偷聽別人的夢話，真是惡趣味。傭兵都是這樣嗎？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"나 같은 보통 사람은 관찰력이 부족하면 살아남을 수 없으니까.","JPN":"俺みたいな普通の人間は、観察力が足りないと生き残れないからな。","ENG":"Folks like us can't survive if we're not very observant.","TWN":"像我這種普通人，要是缺乏觀察力的話。可是沒辦法生存下去的。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그보다 아버지와 사이가 별로 안 좋았었나 보더군.","JPN":"で、親父とは仲があまりよくなかったみたいだな。","ENG":"By the way, it sounds like things weren't exactly peachy between you and your old man.","TWN":"不過，你們父子關係好像不太好啊。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이젠 다 지난 이야기야. 돌아가셨거든.","JPN":"昔の話だ。もうこの世にいないからな。","ENG":"It's all in the past. He's passed away.","TWN":"都已經是過去的事情了，他已經去世了。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......마지막 순간까지 화해를 못 한 건가?","JPN":"……最後まで仲直りできなかったのか？","ENG":"You never got to bury the hatchet?","TWN":"……直到最後一刻都沒能和解嗎？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......남의 가정사에 관심이 많으시군.","JPN":"……他人のことに首を突っ込まないでくれ。","ENG":"You sure are nosy about other people's family history.","TWN":"……您對別人的家事真有興趣呢。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아버진 당신처럼 돈에 눈이 먼 용병이라, 집에 머무는 일이 별로 없었어.","JPN":"父はお前みたいな金に目がくらんだ傭兵だったから、家にほとんどいなかった。","ENG":"My dad was a money-grubbing merc like you. Never stuck around much at home.","TWN":"我父親和你一樣，是個被金錢蒙蔽雙眼的傭兵，所以很少會待在家裡。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"고향 마을에 침식체들이 쳐들어 오던 그 순간에도 말이야.","JPN":"地元に侵食体が押し寄せて来た日もな。","ENG":"He was always gone, even when the C.O.s swarmed over our town.","TWN":"就連故鄉被侵蝕體襲擊時也是。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"심지어 할아버지가 그 때문에 돌아가셨는데도, 얼굴도 내비치지 않았지.","JPN":"しかも、祖父がそのせいで亡くなったのに顔も出さなかったんだ。","ENG":"Grandpa passed away because of that. Even so, my dad never showed his face.","TWN":"甚至爺爺因這場事故去世時，他也沒有露過一次臉。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런 사람을 좋아할 수 있겠어?","JPN":"そんな人間、好きになれないだろう？","ENG":"How could I ever like someone like that?","TWN":"我能喜歡這種人嗎？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......그렇군.","JPN":"……そうか。","ENG":"I see...","TWN":"……這樣啊。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 자네가 알고 있는 게 전부는 아닐 수도 있어.","JPN":"だが、お前が知ってることがすべてだとは限らない。","ENG":"But you might not know the entire truth.","TWN":"但你知道的未必就是一切。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"자고로 아버지란 사람은 자식에게 모든 걸 말할 수 없는 때도 있는 법이거든.","JPN":"父親というものは子供に何もかも打ち明けないものなんだよ。","ENG":"Fathers sometimes can't tell their children everything, you see.","TWN":"很多情況下，做父親的會因為現實問題無法向兒女說出一切。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"서로에게 상처만 되더라도...... 혼자 안고 갈 수밖에 없는 일도 있으니까.","JPN":"お互い傷つくことになっても……一人で抱え込んで行くしかないこともあるのさ。","ENG":"Even if it ends up hurting both of you... There are some things that a father must bear on his own.","TWN":"即使這麼做會傷害彼此……但他們還是不得不獨自承擔一切。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"당신이 뭘 안다고 함부로 말하는 거야?","JPN":"お前に何がわかる！　余計なことを言うな。","ENG":"What the heck would you know about this?","TWN":"你又知道什麼？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그게 사실이라고 한들, 결국 중요한 건 결과라고!","JPN":"仮にそれが事実だとしても、大事なのは結果なんだ！","ENG":"Even if that was the case, the results are what matters the most!","TWN":"就算你說得沒錯，最重要的還是結果！"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......내 딸아이는 침식 증후군 말기야.","JPN":"……俺の娘は侵食症候群末期だ。","ENG":"My daughter... She has terminal Corruption Syndrome.","TWN":"……我的女兒正處於侵蝕症候群晚期。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그 녀석의 치료비를 대느라 밤낮으로 용병일을 하고는 있지만......","JPN":"あいつの治療費を稼ぐために、昼夜傭兵の仕事をしているが……","ENG":"Although I'm working my butt off night and day as a merc to pay off her hospital bills...","TWN":"雖然我為支付那孩子的治療費，沒日沒夜做著雇傭兵的工作……"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"아마도 결국 죽겠지.","JPN":"多分もうじき死ぬだろう。","ENG":"She'll probably die, eventually.","TWN":"但她應該活不久了。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"何……？","ENG":"What?","TWN":"什……？"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"어쩌면 딸아이는 그럴 시간에 조금이라도 더 자기 곁에 있어주기를 바랄 수도 있어.","JPN":"もしかしたら、娘は俺が働く代わりにもう少し自分のそばにいてほしいと思ってるかもしれない。","ENG":"If anything, she might prefer to have me stick around instead of going out there to foot the bill.","TWN":"也許比起做這種事，女兒更希望我能陪陪她吧。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"우리 둘 다 그런 이야기는 하지 않지만...... 그렇더라도 난 이럴 수 밖에 없어","JPN":"娘とこういう話はしないが……それでも俺はこうするしかないんだ。","ENG":"Although neither of us ever say it explicitly... I have no choice but to do what I can do now.","TWN":"雖然我們都沒有說過這些……就算如此，我也別無選擇……"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"난 말이지, 딸 아이가 단 하루라도 더 살 수 있다면 아무것도 더 바라지는 않아.","JPN":"俺はな、娘がただ一日でも長く生きてくれれば、それ以上は何も望まない。","ENG":"You see, the only thing I want is for my daughter to live another day.","TWN":"我啊，只希望女兒能多活一天，除此以外我什麼都不奢望。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 마지막 순간이 왔을 때......","JPN":"だが、最期を迎える時……","ENG":"But when that moment finally comes...","TWN":"但到了最後一刻……"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그래도 그 아이가 내 진심을 알아주면 좋겠다고 생각해.","JPN":"あいつが俺の本気をわかってもらえればいいと思う。","ENG":"I hope she'll understand my true feelings.","TWN":"我還是希望那孩子能夠理解我。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"어쩌면 자네 아버지도 그렇지 않을까?","JPN":"もしかしたら、お前の親父もそうだったのかもしれない。","ENG":"Wouldn't your father have felt the same way?","TWN":"說不定你的父親也和我有同樣的想法。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......가족이란 그런 거니까.","JPN":"……家族ってそういうもんだからな。","ENG":"That's what being family's all about.","TWN":"……因為這就是家人啊。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"슬슬 가야겠군. 작전 참가 시간이라서 말이야.","JPN":"そろそろ失礼するよ。もうすぐ作戦が始まる時間だからな。","ENG":"I'd better get going. There's an operation I've got to join.","TWN":"我差不多該走了。快到作戰開始的時間了。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MASTER_NPC_NULL_NULL","text":{"KOREA":"어이! 피셔! 계산은 하고 가야지!","JPN":"おい！　フィシャー！　会計しろよ！","ENG":"Hey! Fisher! You've got to pay for your drinks!","TWN":"喂！費舍爾！先結帳再走啊！"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"늘 하던 대로, 장부에 달아두라고.","JPN":"いつも通り、つけておけ。","ENG":"Just put on my tab, as usual.","TWN":"跟平時一樣，記帳上吧。"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BAR","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};